import { expect, test } from '@playwright/test';

// TriggersPanel on the seeded suite's detail page: bind an orchestrator
// pipeline (run-on-success, CLAUDE.md §4 — the one place a pipeline id meets a
// suite), toggle it, and remove it. The binding is provider-agnostic
// (`trigger_bindings`); the seeded ADF/Airflow connections make the providers
// real, and a unique pipeline id keeps the composite key (provider, id, env)
// collision-free across runs.
test.describe('Suite triggers panel', () => {
  const card = (page: import('@playwright/test').Page) =>
    page.locator('.ant-card').filter({ hasText: 'orchestrator pipeline' });

  test.beforeEach(async ({ page }) => {
    await page.goto('/suites');
    await page.getByText('Orders quality').click();
    await expect(page).toHaveURL(/\/suites\/[0-9a-f-]+$/);
    await expect(card(page).getByText('Triggers', { exact: true })).toBeVisible();
  });

  test('bind a pipeline, disable it, then remove it', async ({ page }) => {
    const panel = card(page);
    const pipelineId = `e2e_pl_${Date.now()}`;

    // Provider + Env are antd Selects: focus the combobox, wait for the
    // dropdown, keyboard-select the first option (stable against rc-virtual-
    // list measurement, same pattern as suites.spec.ts). DOM order within the
    // panel: [0]=Provider ('adf' first), [1]=Env ('dev' first).
    const combos = panel.getByRole('combobox');
    await combos.first().click();
    await expect(page.locator('.ant-select-dropdown').last()).toBeVisible();
    await combos.first().press('ArrowDown');
    await combos.first().press('Enter');

    await panel.getByPlaceholder('Pipeline / DAG id').fill(pipelineId);

    await combos.nth(1).click();
    await expect(page.locator('.ant-select-dropdown').last()).toBeVisible();
    await combos.nth(1).press('ArrowDown');
    await combos.nth(1).press('Enter');

    await panel.getByRole('button', { name: 'Add' }).click();
    await expect(page.getByText(`${pipelineId}: trigger added`)).toBeVisible();

    // Listed with its provider label and enabled by default.
    const row = panel.locator('[role="listitem"]').filter({ hasText: pipelineId });
    await expect(row).toBeVisible();
    await expect(row.getByText('Azure Data Factory')).toBeVisible();
    await expect(row.getByRole('switch')).toBeChecked();

    // Disable (run-on-success stops firing without losing the binding).
    await row.getByRole('switch').click();
    await expect(page.getByText(`${pipelineId}: disabled`)).toBeVisible();

    // Remove — immediate (no confirm) — and the row disappears.
    await row.getByRole('button', { name: `Remove ${pipelineId}` }).click();
    await expect(page.getByText(`${pipelineId}: removed`)).toBeVisible();
    await expect(panel.locator('[role="listitem"]').filter({ hasText: pipelineId })).toHaveCount(
      0,
    );
  });
});

import { expect, test } from '@playwright/test';

// NotificationsPanel on the seeded suite's detail page: per-suite alerting
// config (W6 — fronts notification_service). Sets a deterministic state
// (enabled + warn threshold), saves, and proves it survives a reload. The
// Teams webhook stays untouched — it's write-only (the API never returns it)
// and writing one would push a secret into the store; the spec only asserts
// the write-only affordance renders.
test.describe('Suite notifications panel', () => {
  const card = (page: import('@playwright/test').Page) =>
    page.locator('.ant-card').filter({ hasText: 'run outcomes to Microsoft Teams' });

  const openSuite = async (page: import('@playwright/test').Page) => {
    await page.goto('/suites');
    await page.getByText('Orders quality').click();
    await expect(page).toHaveURL(/\/suites\/[0-9a-f-]+$/);
    await expect(card(page).getByText('Notifications', { exact: true })).toBeVisible();
  };

  test('configure threshold routing and persist it across a reload', async ({ page }) => {
    await openSuite(page);
    const panel = card(page);

    // Deterministic target state: enabled + "On warn and worse".
    const enable = panel.getByRole('switch', { name: 'Enable notifications' });
    if (!(await enable.isChecked())) {
      await enable.click();
    }
    const threshold = panel.getByRole('combobox');
    await threshold.click();
    await expect(page.locator('.ant-select-dropdown').last()).toBeVisible();
    await page.getByRole('option', { name: 'On warn and worse' }).click();

    await panel.getByRole('button', { name: 'Save' }).click();
    await expect(page.getByText('Notifications saved')).toBeVisible();

    // Reload → the form re-seeds from the API with the saved values.
    await page.reload();
    await expect(card(page).getByText('On warn and worse')).toBeVisible();
    await expect(card(page).getByRole('switch', { name: 'Enable notifications' })).toBeChecked();
  });

  test('webhook is a write-only secret affordance', async ({ page }) => {
    await openSuite(page);
    const panel = card(page);

    // The field never echoes a stored URL — just a set/not-set tag + password
    // input. (Writing one is out of scope: it lands a secret in the store.)
    await expect(panel.getByText('Teams webhook')).toBeVisible();
    await expect(panel.getByLabel('Teams webhook URL')).toBeVisible();
    await expect(panel.getByText(/^(set|not set)$/)).toBeVisible();
  });
});

