import fs from 'node:fs';
import path from 'node:path';

import { chromium } from '@playwright/test';

// One interactive login per session: launches a HEADED browser at the live
// URL, waits for a human to complete the real OIDC sign-in (MFA and all), then
// serializes sessionStorage to a gitignored file the specs replay via
// addInitScript. sessionStorage (not cookies/localStorage) because
// oidc-client-ts keeps the signed-in user there (authClient.ts
// WebStorageStateStore) — Playwright's built-in storageState can't capture it.
//
// The captured token expires like any AAD token (~1h); the file is reused
// while fresh and re-captured otherwise.

export const SESSION_FILE = path.join(__dirname, '.auth', 'session.json');
const MAX_AGE_MS = 40 * 60 * 1000; // re-login when the capture is older than 40 min

export default async function globalSetup(): Promise<void> {
  const liveBaseURL = process.env.E2E_LIVE_BASE_URL;
  if (!liveBaseURL) {
    throw new Error('live-smoke lane requires E2E_LIVE_BASE_URL');
  }
  if (fs.existsSync(SESSION_FILE)) {
    const age = Date.now() - fs.statSync(SESSION_FILE).mtimeMs;
    if (age < MAX_AGE_MS) {
      return; // fresh enough — reuse
    }
  }

  const browser = await chromium.launch({ headless: false });
  const page = await browser.newPage();
  await page.goto(liveBaseURL);
  // eslint-disable-next-line no-console
  console.log('\n[live-smoke] Complete the sign-in in the opened browser…');
  // The post-login landing is the Dashboard; give MFA up to 5 minutes.
  await page
    .getByRole('heading', { name: 'Dashboard', level: 3 })
    .waitFor({ timeout: 300_000 });
  const session: string = await page.evaluate(() => JSON.stringify({ ...sessionStorage }));
  fs.mkdirSync(path.dirname(SESSION_FILE), { recursive: true });
  fs.writeFileSync(SESSION_FILE, session);
  await browser.close();
  // eslint-disable-next-line no-console
  console.log('[live-smoke] Session captured.');
}

import fs from 'node:fs';

import { test as base } from '@playwright/test';

import { SESSION_FILE } from './global-setup';

/** `test` for live-smoke specs: replays the captured OIDC sessionStorage into
 *  every new document before any app code runs, so the SPA boots signed-in. */
export const test = base.extend({
  context: async ({ context }, use) => {
    const entries: Record<string, string> = JSON.parse(fs.readFileSync(SESSION_FILE, 'utf8'));
    await context.addInitScript((stored) => {
      for (const [key, value] of Object.entries(stored)) {
        sessionStorage.setItem(key, value);
      }
    }, entries);
    await use(context);
  },
});

export { expect } from '@playwright/test';

import { expect, test } from './live-test';

// Read-only live smoke against the DEPLOYED app + the ADR 0021 harness data.
// Opt-in only (E2E_LIVE_BASE_URL) — never runs in CI. Signed in via the
// sessionStorage captured by global-setup (real OIDC). Nothing here mutates:
// triggering live runs / alert delivery stays on the manual checklist
// (docs/runbook-faq.md).
//
// The expected suite is env-tunable: E2E_LIVE_SUITE (default the "Retail
// Orders" demo suite the prod workspace carries; the harness flows also land
// flow_a_snowflake / flow_b_* suites).
const LIVE_SUITE = process.env.E2E_LIVE_SUITE || 'Retail Orders';

test('dashboard renders live KPIs', async ({ page }) => {
  await page.goto('/dashboard');
  await expect(page.getByRole('heading', { name: 'Dashboard', level: 3 })).toBeVisible();
  for (const label of ['Data Integrity Score', 'Pass Rate', 'Total Runs', 'Active Connections']) {
    await expect(page.getByText(label, { exact: true })).toBeVisible();
  }
});

test(`suites list shows the live suite ("${LIVE_SUITE}") and its checks`, async ({ page }) => {
  await page.goto('/suites');
  await expect(page.getByRole('heading', { name: 'Suites', level: 3 })).toBeVisible();
  await page.getByText(LIVE_SUITE).first().click();
  await expect(page).toHaveURL(/\/suites\/[0-9a-f-]+$/);
  await expect(page.getByRole('heading', { name: LIVE_SUITE, level: 4 })).toBeVisible();
});

test('results page lists runs and a run detail opens', async ({ page }) => {
  await page.goto('/results');
  await expect(page.getByRole('heading', { name: 'Results', level: 3 })).toBeVisible();
  const firstRun = page.locator('tr.ant-table-row').first();
  await expect(firstRun).toBeVisible();
  await firstRun.click();
  await expect(page).toHaveURL(/\/results\/[0-9a-f-]+$/);
});

