6	// One interactive login per session: launches a HEADED browser at the live
7	// URL, waits for a human to complete the real OIDC sign-in (MFA and all), then
8	// serializes sessionStorage to a gitignored file the specs replay via
9	// addInitScript. sessionStorage (not cookies/localStorage) because
10	// oidc-client-ts keeps the signed-in user there (authClient.ts
11	// WebStorageStateStore) — Playwright's built-in storageState can't capture it.
12	//
13	// The captured token expires like any AAD token (~1h); the file is reused
14	// while fresh and re-captured otherwise.
15	
16	// cwd-relative (pnpm runs from frontend/): __dirname doesn't exist under ESM.
17	export const SESSION_FILE = path.resolve('e2e-live', '.auth', 'session.json');
18	const MAX_AGE_MS = 40 * 60 * 1000; // re-login when the capture is older than 40 min
19	
20	export default async function globalSetup(): Promise<void> {
21	  const liveBaseURL = process.env.E2E_LIVE_BASE_URL;
22	  if (!liveBaseURL) {
23	    throw new Error('live-smoke lane requires E2E_LIVE_BASE_URL');
24	  }
25	  if (fs.existsSync(SESSION_FILE)) {
26	    const age = Date.now() - fs.statSync(SESSION_FILE).mtimeMs;
27	    if (age < MAX_AGE_MS) {
28	      return; // fresh enough — reuse
29	    }
30	  }
31	
32	  const browser = await chromium.launch({ headless: false });
33	  const page = await browser.newPage();
34	  await page.goto(liveBaseURL);
35	  console.log('\n[live-smoke] Complete the sign-in in the opened browser…');
36	  // The post-login landing is the Dashboard; give MFA up to 5 minutes.
37	  await page.getByRole('heading', { name: 'Dashboard', level: 3 }).waitFor({ timeout: 300_000 });
38	  const session: string = await page.evaluate(() => JSON.stringify({ ...sessionStorage }));
39	  fs.mkdirSync(path.dirname(SESSION_FILE), { recursive: true });
40	  fs.writeFileSync(SESSION_FILE, session);
41	  await browser.close();
42	  console.log('[live-smoke] Session captured.');
43	}
